class StatefulFirewall:
    def __init__(self):
        self.state_table = {}  # Tracks active connections
        self.rules = []

    def check_packet(self, packet):
        conn_id = (packet.src_ip, packet.src_port, 
                   packet.dest_ip, packet.dest_port)

        # Check if packet belongs to established connection
        if conn_id in self.state_table:
            return "ALLOW"

        # Check against rules for new connections
        for rule in self.rules:
            if self.match_rule(packet, rule):
                if rule['action'] == 'ALLOW':
                    # Add to state table for new allowed connections
                    self.state_table[conn_id] = 'ESTABLISHED'
                return rule['action']

        return "DENY"

    def match_rule(self, packet, rule):
        return (packet.dest_port == rule.get('port') and
                packet.protocol == rule.get('protocol'))

    def cleanup_stale_connections(self):
        # Remove connections older than timeout
        current_time = time.time()
        stale = [k for k, v in self.state_table.items() 
                 if current_time - v['timestamp'] > 300]
        for conn in stale:
            del self.state_table[conn]

// Structure for firewall rule
typedef struct {
    uint32_t src_ip;
    uint32_t src_mask;
    uint32_t dest_ip;
    uint32_t dest_mask;
    uint16_t src_port_start;
    uint16_t src_port_end;
    uint16_t dest_port_start;
    uint16_t dest_port_end;
    uint8_t protocol;  // TCP=6, UDP=17, ICMP=1
    uint8_t action;    // ALLOW=1, DENY=0
} FirewallRule;

// Function to check if IP matches rule
int ip_match(uint32_t ip, uint32_t rule_ip, uint32_t mask) {
    return (ip & mask) == (rule_ip & mask);
}

// Function to evaluate packet against rules
uint8_t evaluate_packet(Packet *pkt, FirewallRule *rules, int count) {
    for (int i = 0; i < count; i++) {
        if (ip_match(pkt->src_ip, rules[i].src_ip, rules[i].src_mask) &&
            ip_match(pkt->dest_ip, rules[i].dest_ip, rules[i].dest_mask) &&
            pkt->protocol == rules[i].protocol &&
            port_in_range(pkt->dest_port, rules[i].dest_port_start, 
                         rules[i].dest_port_end)) {
            return rules[i].action;
        }
    }
    return DENY;  // Implicit deny
}

# Example Snort IDS rules for detecting various attacks

# Rule 1: Detect ICMP (ping) sweep
alert icmp any any -> any any (msg:"ICMP Ping Sweep"; 
       sid:1000001; rev:1;)

# Rule 2: Detect SSH brute force attempt
alert tcp any any -> $HOME_NET 22 (msg:"SSH Brute Force"; 
       flow:to_server; threshold:type both, count 5, seconds 60;
       sid:1000002; rev:1;)

# Rule 3: Detect potential DDoS (SYN flood)
alert tcp any any -> $HOME_NET any (msg:"Possible SYN Flood"; 
       flags:S; flow:to_server; threshold:type threshold, 
       track by_src, count 1000, seconds 10;
       sid:1000003; rev:1;)

# Rule 4: Detect ARP spoofing (ARP reply to unreplied request)
alert arp any any -> any any (msg:"ARP Spoofing Detected"; 
       sid:1000004; rev:1;)

# Rule 5: Detect DNS poisoning attempt
alert udp any 53 -> any any (msg:"DNS Query Response"; 
       content:"|00 00 01 00 01|"; offset:4;
       sid:1000005; rev:1;)
